const tags = [];
document.getElementById('add-location').addEventListener('click', () => { const val = locationInput.value.trim(); if (!val) return; tags.push(val); renderTags(); locationInput.value = ''; nextBtn.disabled = false; });
function renderTags() { tagsDiv.innerHTML = tags.map((t, i) => '<span class="tag">' + t + '<button onclick="removeTag(' + i + ')">✕</button></span>').join(''); }
function removeTag(i) { tags.splice(i, 1); renderTags(); nextBtn.disabled = tags.length === 0; }
